package main

import (
	"html/template"
	"log"
	"net/http"
	"time"
)

type Comment struct {
	Author string
	Body   template.HTML
	Time   time.Time
}

var comments = []Comment{
	{
		Author: "Alice",
		Body:   template.HTML("Hello, <b>world</b>!"),
		Time:   time.Now().Add(-2 * time.Hour),
	},
	{
		Author: "Bob",
		Body:   template.HTML("I like <i>Go</i> and <strong>templates</strong>."),
		Time:   time.Now().Add(-45 * time.Minute),
	},
	{
		Author: "Carol",
		Body:   template.HTML("Visit <a href=\"https://golang.org\">the Go website</a>."),
		Time:   time.Now().Add(-10 * time.Minute),
	},
}

var pageTmpl = template.Must(template.New("comments").Parse(`
<!doctype html>
<html lang="en">
<head>
	<meta charset="utf-8">
	<title>User Comments</title>
	<style>
		body { font-family: sans-serif; margin: 2rem; }
		.comment { border-bottom: 1px solid #ddd; padding: 1rem 0; }
		.author { font-weight: bold; }
		.time { color: #666; font-size: 0.9rem; margin-left: 0.5rem; }
		.body { margin-top: 0.5rem; }
	</style>
</head>
<body>
	<h1>User Comments</h1>
	{{if .}}
		{{range .}}
			<div class="comment">
				<div>
					<span class="author">{{.Author}}</span>
					<span class="time">{{.Time.Format "2006-01-02 15:04:05"}}</span>
				</div>
				<div class="body">{{.Body}}</div>
			</div>
		{{end}}
	{{else}}
		<p>No comments yet.</p>
	{{end}}
</body>
</html>
`))

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	if r.URL.Path != "/" {
		http.NotFound(w, r)
		return
	}

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	if err := pageTmpl.Execute(w, comments); err != nil {
		http.Error(w, "failed to render comments", http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/", commentsHandler)

	log.Println("listening on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}